const PROVIDER_ICON_MAP: Record<string, (className: string) => ReactNode> = {
  goose: (className) => (
    <GooseIcon className={`${className} text-foreground`} />
  ),
  "claude-acp": (className) => <ClaudeIcon className={className} />,
  "claude-code": (className) => <ClaudeIcon className={className} />,
  claude: (className) => <ClaudeIcon className={className} />,
  anthropic: (className) => <ClaudeIcon className={className} />,
  codex: (className) => <CodexIcon className={className} />,
  "codex-acp": (className) => <CodexIcon className={className} />,
  openai: (className) => <OpenAIIcon className={className} />,
  chatgpt_codex: (className) => <CodexIcon className={className} />,
  google: (className) => <GoogleGeminiIcon className={className} />,
  "copilot-acp": (className) => <CopilotIcon className={className} />,
  github_copilot: (className) => <CopilotIcon className={className} />,
  "cursor-agent": (className) => <CursorIcon className={className} />,
  cursor: (className) => <CursorIcon className={className} />,
  amp: (className) => <AmpIcon className={className} />,
  "amp-acp": (className) => <AmpIcon className={className} />,
  azure: (className) => <AzureOpenAIIcon className={className} />,
  bedrock: (className) => <BedrockIcon className={className} />,
  databricks: (className) => <DatabricksIcon className={className} />,
  gcp_vertex_ai: (className) => <VertexAIIcon className={className} />,
  ollama: (className) => <OllamaIcon className={className} />,
  openrouter: (className) => <OpenRouterIcon className={className} />,
  snowflake: (className) => <SnowflakeIcon className={className} />,
  xai: (className) => <XAIIcon className={className} />,
};

function normalizeProviderId(providerId: string) {
  return providerId
    .toLowerCase()
    .split(/[-_\s]+/)
    .filter(Boolean)
    .join("_");
}

const NORMALIZED_PROVIDER_ICON_MAP = Object.fromEntries(
  Object.entries(PROVIDER_ICON_MAP).map(([key, render]) => [
    normalizeProviderId(key),
    render,
  ]),
) as Record<string, (className: string) => ReactNode>;

export function formatProviderLabel(providerId: string) {
  return providerId
    .split(/[-_\s]+/)
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

export function getProviderIcon(
  providerId: string,
  className = "size-4",
): ReactNode | null {
  const normalizedId = normalizeProviderId(providerId);

  if (NORMALIZED_PROVIDER_ICON_MAP[normalizedId]) {
    return NORMALIZED_PROVIDER_ICON_MAP[normalizedId](className);
  }

  for (const [key, render] of Object.entries(NORMALIZED_PROVIDER_ICON_MAP)) {
    if (normalizedId.includes(key)) {
      return render(className);
    }
  }

  return null;
}
